+@page "/board"
+@rendermode InteractiveServer
+@inject ITaskService TaskService
+
+<PageTitle>Kanban Board</PageTitle>
+
+<h1>Project Board</h1>
+
+@if (_loading)
+{
+    <p><em>Loading tasks...</em></p>
+}
+else if (_error is not null)
+{
+    <div class="alert alert-danger">@_error</div>
+}
+else
+{
+    <!-- Stats Bar -->
+    <div class="stats-bar">
+        <span class="stat-item"><strong>Total:</strong> @_filteredTasks.Count</span>
+        <span class="stat-item"><strong>To Do:</strong> @GetColumnTasks("To Do").Count</span>
+        <span class="stat-item"><strong>In Progress:</strong> @GetColumnTasks("In Progress").Count</span>
+        <span class="stat-item"><strong>Done:</strong> @GetColumnTasks("Done").Count</span>
+        <span class="stat-item stat-overdue"><strong>Overdue:</strong> @_filteredTasks.Count(t => t.DueDate < DateTime.Today)</span>
+    </div>
+
+    <!-- Search Bar -->
+    <div class="search-bar">
+        <input type="text" class="form-control" placeholder="Search tasks by title..."
+               @bind="_searchText" @bind:event="oninput" />
+    </div>
+
+    <!-- Kanban Columns -->
+    <div class="kanban-board">
+        @foreach (var column in _columns)
+        {
+            var tasks = GetColumnTasks(column);
+            <div class="kanban-column">
+                <div class="column-header">
+                    <h3>@column <span class="badge bg-secondary">@tasks.Count</span></h3>
+                </div>
+                <div class="column-body">
+                    @foreach (var task in tasks)
+                    {
+                        <div class="task-card">
+                            <div class="task-title">@task.Title</div>
+                            <div class="task-assignee">@task.Assignee</div>
+                            <span class="priority-badge priority-@task.Priority.ToLower()">@task.Priority</span>
+                            <div class="task-due">@task.DueDate.ToString("MMM dd")</div>
+                            <div class="task-actions">
+                                @if (GetColumnIndex(column) > 0)
+                                {
+                                    <button class="btn btn-sm btn-outline-secondary"
+                                            @onclick="() => MoveTask(task.Id, _columns[GetColumnIndex(column) - 1])">
+                                        &larr; Move Left
+                                    </button>
+                                }
+                                @if (GetColumnIndex(column) < _columns.Length - 1)
+                                {
+                                    <button class="btn btn-sm btn-outline-secondary"
+                                            @onclick="() => MoveTask(task.Id, _columns[GetColumnIndex(column) + 1])">
+                                        Move Right &rarr;
+                                    </button>
+                                }
+                            </div>
+                        </div>
+                    }
+                </div>
+
+                @if (_showForm == column)
+                {
+                    <div class="add-task-form">
+                        <input type="text" class="form-control mb-1" placeholder="Title"
+                               @bind="_newTitle" />
+                        <input type="text" class="form-control mb-1" placeholder="Assignee"
+                               @bind="_newAssignee" />
+                        <select class="form-select mb-1" @bind="_newPriority">
+                            <option value="High">High</option>
+                            <option value="Medium">Medium</option>
+                            <option value="Low">Low</option>
+                        </select>
+                        <input type="date" class="form-control mb-1" @bind="_newDueDate" />
+                        <div class="form-buttons">
+                            <button class="btn btn-primary btn-sm" @onclick="() => SaveTask(column)">Save</button>
+                            <button class="btn btn-secondary btn-sm" @onclick="CancelForm">Cancel</button>
+                        </div>
+                    </div>
+                }
+                else
+                {
+                    <button class="btn btn-outline-primary btn-sm add-task-btn" @onclick="() => ShowForm(column)">
+                        + Add Task
+                    </button>
+                }
+            </div>
+        }
+    </div>
+}
+
+<style>
+    .stats-bar {
+        display: flex;
+        gap: 1.5rem;
+        padding: 0.75rem 1rem;
+        background: #f8f9fa;
+        border-radius: 0.5rem;
+        margin-bottom: 1rem;
+        flex-wrap: wrap;
+    }
+    .stat-overdue { color: #dc3545; }
+    .search-bar { margin-bottom: 1rem; max-width: 400px; }
+    .kanban-board {
+        display: flex;
+        gap: 1rem;
+        align-items: flex-start;
+    }
+    .kanban-column {
+        flex: 1;
+        background: #f1f3f5;
+        border-radius: 0.5rem;
+        padding: 0.75rem;
+        min-width: 250px;
+    }
+    .column-header h3 { font-size: 1.1rem; margin: 0 0 0.5rem; }
+    .task-card {
+        background: #fff;
+        border: 1px solid #dee2e6;
+        border-radius: 0.4rem;
+        padding: 0.75rem;
+        margin-bottom: 0.5rem;
+    }
+    .task-title { font-weight: 600; margin-bottom: 0.25rem; }
+    .task-assignee { font-size: 0.85rem; color: #6c757d; margin-bottom: 0.25rem; }
+    .task-due { font-size: 0.85rem; color: #495057; margin-top: 0.25rem; }
+    .task-actions { margin-top: 0.5rem; display: flex; gap: 0.25rem; }
+    .priority-badge {
+        display: inline-block;
+        padding: 0.15rem 0.5rem;
+        border-radius: 0.25rem;
+        font-size: 0.75rem;
+        font-weight: 600;
+        color: #fff;
+    }
+    .priority-high { background-color: #dc3545; }
+    .priority-medium { background-color: #ffc107; color: #212529; }
+    .priority-low { background-color: #198754; }
+    .add-task-form { padding: 0.5rem; background: #fff; border-radius: 0.4rem; border: 1px solid #dee2e6; }
+    .form-buttons { display: flex; gap: 0.5rem; }
+    .add-task-btn { width: 100%; margin-top: 0.5rem; }
+</style>
+
+@code {
+    private readonly string[] _columns = { "To Do", "In Progress", "Done" };
+    private List<TaskItem> _allTasks = new();
+    private List<TaskItem> _filteredTasks = new();
+    private bool _loading = true;
+    private string? _error;
+    private string _searchText = string.Empty;
+
+    // Form state
+    private string? _showForm;
+    private string _newTitle = string.Empty;
+    private string _newAssignee = string.Empty;
+    private string _newPriority = "Medium";
+    private DateTime _newDueDate = DateTime.Today.AddDays(7);
+
+    protected override async Task OnInitializedAsync()
+    {
+        try
+        {
+            _allTasks = await TaskService.GetAllTasksAsync();
+            ApplyFilter();
+        }
+        catch (Exception ex)
+        {
+            _error = $"Failed to load tasks: {ex.Message}";
+        }
+        finally
+        {
+            _loading = false;
+        }
+    }
+
+    private string _lastSearchText = string.Empty;
+
+    private void ApplyFilter()
+    {
+        if (string.IsNullOrWhiteSpace(_searchText))
+            _filteredTasks = _allTasks;
+        else
+            _filteredTasks = _allTasks
+                .Where(t => t.Title.Contains(_searchText, StringComparison.OrdinalIgnoreCase))
+                .ToList();
+        _lastSearchText = _searchText;
+    }
+
+    private List<TaskItem> GetColumnTasks(string status)
+    {
+        ApplyFilterIfNeeded();
+        return _filteredTasks.Where(t => t.Status == status).ToList();
+    }
+
+    private void ApplyFilterIfNeeded()
+    {
+        if (_lastSearchText != _searchText)
+            ApplyFilter();
+    }
+
+    private int GetColumnIndex(string column) => Array.IndexOf(_columns, column);
+
+    private async Task MoveTask(int taskId, string newStatus)
+    {
+        try
+        {
+            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
+            var task = _allTasks.First(t => t.Id == taskId);
+            var index = _allTasks.IndexOf(task);
+            _allTasks[index] = task with { Status = newStatus };
+            ApplyFilter();
+        }
+        catch (Exception ex)
+        {
+            _error = $"Failed to move task: {ex.Message}";
+        }
+    }
+
+    private void ShowForm(string column)
+    {
+        _showForm = column;
+        _newTitle = string.Empty;
+        _newAssignee = string.Empty;
+        _newPriority = "Medium";
+        _newDueDate = DateTime.Today.AddDays(7);
+    }
+
+    private void CancelForm() => _showForm = null;
+
+    private async Task SaveTask(string column)
+    {
+        if (string.IsNullOrWhiteSpace(_newTitle))
+            return;
+
+        try
+        {
+            var created = await TaskService.CreateTaskAsync(_newTitle, _newAssignee, _newPriority, _newDueDate);
+            _allTasks.Add(created with { Status = column });
+            ApplyFilter();
+            _showForm = null;
+        }
+        catch (Exception ex)
+        {
+            _error = $"Failed to create task: {ex.Message}";
+        }
+    }
+}
+

